import React, { useEffect, useState } from "react";
import StatusBadge from "./StatusBadge";
import { normalizeStatus } from "./statusConfig";

const RECORDS_PER_PAGE = 10;
const SORT_OPTIONS = [
  { value: "newest", label: "Latest first", shortLabel: "Latest" },
  { value: "oldest", label: "Oldest first", shortLabel: "Oldest" },
  { value: "lowest-ttc", label: "Lowest TTC", shortLabel: "Low TTC" },
  { value: "highest-ttc", label: "Highest TTC", shortLabel: "High TTC" },
  { value: "lowest-distance", label: "Closest distance", shortLabel: "Closest" },
  { value: "highest-speed", label: "Highest rel. velocity", shortLabel: "Fastest" },
];

function sortHistory(records, sortBy) {
  const sorted = [...records];

  sorted.sort((a, b) => {
    if (sortBy === "oldest") {
      return new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime();
    }

    if (sortBy === "highest-ttc" || sortBy === "lowest-ttc") {
      const aTtc = a.ttc === null ? Number.POSITIVE_INFINITY : a.ttc;
      const bTtc = b.ttc === null ? Number.POSITIVE_INFINITY : b.ttc;
      return sortBy === "highest-ttc" ? bTtc - aTtc : aTtc - bTtc;
    }

    if (sortBy === "lowest-distance") {
      return a.distance - b.distance;
    }

    if (sortBy === "highest-speed") {
      return b.relative_velocity - a.relative_velocity;
    }

    return new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime();
  });

  return sorted;
}

function formatTimestamp(timestamp) {
  return new Intl.DateTimeFormat("en-IN", {
    day: "2-digit",
    month: "short",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  }).format(new Date(timestamp));
}

function getHeaderSortMeta(sortBy, headerKey) {
  if (headerKey === "timestamp") {
    return {
      active: sortBy === "newest" || sortBy === "oldest",
      direction: sortBy === "oldest" ? "asc" : "desc",
      nextSort: sortBy === "oldest" ? "newest" : "oldest",
    };
  }

  if (headerKey === "distance") {
    return {
      active: sortBy === "lowest-distance",
      direction: "asc",
      nextSort: "lowest-distance",
    };
  }

  if (headerKey === "ttc") {
    return {
      active: sortBy === "lowest-ttc" || sortBy === "highest-ttc",
      direction: sortBy === "highest-ttc" ? "desc" : "asc",
      nextSort: sortBy === "highest-ttc" ? "lowest-ttc" : "highest-ttc",
    };
  }

  return {
    active: sortBy === "highest-speed",
    direction: "desc",
    nextSort: "highest-speed",
  };
}

function HistoryView({ history, histLoading }) {
  const [currentPage, setCurrentPage] = useState(1);
  const [statusFilter, setStatusFilter] = useState("All");
  const [sortBy, setSortBy] = useState("newest");

  const statusOptions = [
    "All",
    ...new Set(history.map((row) => normalizeStatus(row.predicted_status)).filter(Boolean)),
  ];
  const filteredHistory =
    statusFilter === "All"
      ? history
      : history.filter((row) => normalizeStatus(row.predicted_status) === statusFilter);
  const sortedHistory = sortHistory(filteredHistory, sortBy);

  useEffect(() => {
    setCurrentPage(1);
  }, [history, histLoading, statusFilter, sortBy]);

  const totalPages = Math.ceil(sortedHistory.length / RECORDS_PER_PAGE);
  const startIndex = (currentPage - 1) * RECORDS_PER_PAGE;
  const visibleHistory = sortedHistory.slice(startIndex, startIndex + RECORDS_PER_PAGE);
  const pageStart = sortedHistory.length === 0 ? 0 : startIndex + 1;
  const pageEnd = Math.min(startIndex + RECORDS_PER_PAGE, sortedHistory.length);

  return (
    <section className="panel mainPanel">
      <div className="historyViewHeader">
        <div>
          <h2>Prediction History</h2>
          <p>Sort by time, TTC, distance, or closing speed without leaving the table context.</p>
        </div>
        <div className="historyControls">
          <label className="historyFilter">
            <span>Status</span>
            <select
              className="historyFilterSelect"
              value={statusFilter}
              onChange={(event) => setStatusFilter(event.target.value)}
            >
              {statusOptions.map((status) => (
                <option key={status} value={status}>
                  {status}
                </option>
              ))}
            </select>
          </label>
          <div className="historySortBlock">
            <span className="historySortLabel">Sort</span>
            <div className="historySortOptions">
              {SORT_OPTIONS.map((option) => (
                <button
                  key={option.value}
                  type="button"
                  className={`historySortChip ${sortBy === option.value ? "active" : ""}`}
                  onClick={() => setSortBy(option.value)}
                  aria-pressed={sortBy === option.value}
                >
                  {option.shortLabel}
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>

      <div className="historyCard">
        {histLoading ? (
          <div className="tableSkeleton" aria-hidden="true">
            <div className="skeletonLine skeletonLineWide" />
            <div className="skeletonLine" />
            <div className="skeletonLine" />
            <div className="skeletonLine" />
          </div>
        ) : history.length === 0 ? (
          <div className="emptyState">
            <strong>No history yet</strong>
            <p>Prediction records will appear here after you run the first safety check.</p>
          </div>
        ) : filteredHistory.length === 0 ? (
          <div className="emptyState">
            <strong>No matching records</strong>
            <p>Try another status filter to see more prediction history.</p>
          </div>
        ) : (
          <>
            <table className="historyTable">
              <thead>
                <tr>
                  <th>#</th>
                  <th>
                    <button
                      type="button"
                      className={`historyHeaderButton ${
                        getHeaderSortMeta(sortBy, "timestamp").active ? "active" : ""
                      }`}
                      onClick={() => setSortBy(getHeaderSortMeta(sortBy, "timestamp").nextSort)}
                    >
                      Time
                      <span>{getHeaderSortMeta(sortBy, "timestamp").direction === "asc" ? "↑" : "↓"}</span>
                    </button>
                  </th>
                  <th>
                    <button
                      type="button"
                      className={`historyHeaderButton ${
                        getHeaderSortMeta(sortBy, "distance").active ? "active" : ""
                      }`}
                      onClick={() => setSortBy(getHeaderSortMeta(sortBy, "distance").nextSort)}
                    >
                      Distance
                      <span>↑</span>
                    </button>
                  </th>
                  <th>
                    <button
                      type="button"
                      className={`historyHeaderButton ${
                        getHeaderSortMeta(sortBy, "ttc").active ? "active" : ""
                      }`}
                      onClick={() => setSortBy(getHeaderSortMeta(sortBy, "ttc").nextSort)}
                    >
                      TTC
                      <span>{getHeaderSortMeta(sortBy, "ttc").direction === "asc" ? "↑" : "↓"}</span>
                    </button>
                  </th>
                  <th>
                    <button
                      type="button"
                      className={`historyHeaderButton ${
                        getHeaderSortMeta(sortBy, "relative_velocity").active ? "active" : ""
                      }`}
                      onClick={() => setSortBy(getHeaderSortMeta(sortBy, "relative_velocity").nextSort)}
                    >
                      Rel. Velocity
                      <span>↓</span>
                    </button>
                  </th>
                  <th>Status</th>
                </tr>
              </thead>
              <tbody>
                {visibleHistory.map((row) => (
                  <tr key={row.id}>
                    <td>{row.id}</td>
                    <td>{formatTimestamp(row.timestamp)}</td>
                    <td>{row.distance.toFixed(1)} m</td>
                    <td>{row.ttc === null ? "N/A" : `${row.ttc.toFixed(2)} s`}</td>
                    <td>{row.relative_velocity.toFixed(1)} m/s</td>
                    <td>
                      <StatusBadge status={row.predicted_status} />
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>

            <div className="historyPagination">
              <span className="historyPageInfo">
                Showing {pageStart}-{pageEnd} of {sortedHistory.length} records
              </span>

              {totalPages > 1 ? (
                <div className="historyPaginationActions">
                  <span className="historyPageInfo">
                    Page {currentPage} of {totalPages}
                  </span>
                  <button
                    type="button"
                    className="historyPageButton"
                    onClick={() => setCurrentPage((page) => page - 1)}
                    disabled={currentPage === 1}
                  >
                    Previous
                  </button>
                  <button
                    type="button"
                    className="historyPageButton"
                    onClick={() => setCurrentPage((page) => page + 1)}
                    disabled={currentPage === totalPages}
                  >
                    Next Page
                  </button>
                </div>
              ) : null}
            </div>
          </>
        )}
      </div>
    </section>
  );
}

export default HistoryView;
